{
    "level": "A2–B1",
    "intro": "In this topic you will learn the rules for using the article <strong>the</strong> with <strong>geographical names</strong> - when it is needed and when you can do without it.",
    "rules": [
        {
            "label": "Without THE",
            "color": "emerald",
            "text": "<strong>Most countries and cities</strong> — without article:",
            "example": "Ukraine, London, Paris, Italy"
        },
        {
            "label": "WITH THE",
            "color": "blue",
            "text": "<strong>Oceans, rivers, mountains</strong> — with article:",
            "example": "the Pacific, the Dnipro, the Alps"
        },
        {
            "label": "Exceptions",
            "color": "amber",
            "text": "<strong>Union countries</strong> — with article:",
            "example": "the USA, the UK, the Netherlands"
        }
    ]
}

{
    "title": "1. General rule",
    "intro": "The article with geographical names depends on the object type:",
    "items": [
        {
            "label": "Without THE",
            "title": "Countries, cities, continents",
            "subtitle": "Ukraine, London, Europe - most do not need the article"
        },
        {
            "label": "With THE",
            "title": "Oceans, rivers, mountains",
            "subtitle": "the Pacific, the Dnipro, the Alps - always with an article"
        },
        {
            "label": "Exceptions",
            "title": "Unions and plural",
            "subtitle": "the USA, the UK, the Philippines - special cases"
        }
    ]
}

{
    "title": "2. Countries - no article (most)",
    "sections": [
        {
            "label": "Most countries - Ø",
            "color": "emerald",
            "description": "<strong>Most countries</strong> use <strong>without an article</strong>.",
            "examples": [
                {
                    "en": "Ukraine, Poland, Germany, France",
                    "ua": "Ukraine, Poland, Germany, France"
                },
                {
                    "en": "Italy, Spain, Portugal, Greece",
                    "ua": "Italy, Spain, Portugal, Greece"
                },
                {
                    "en": "Japan, China, India, Australia",
                    "ua": "Japan, China, India, Australia"
                },
                {
                    "en": "I live in Ukraine.",
                    "ua": "I live in Ukraine."
                }
            ]
        },
        {
            "label": "Union countries THE",
            "color": "blue",
            "description": "<strong>Union countries</strong> or names in the <strong>plural</strong> — with the article <strong>the</strong>.",
            "examples": [
                {
                    "en": "the United States (the USA)",
                    "ua": "United States (USA)"
                },
                {
                    "en": "the United Kingdom (the UK)",
                    "ua": "United Kingdom (Great Britain)"
                },
                {
                    "en": "the United Arab Emirates (the UAE)",
                    "ua": "United Arab Emirates (UAE)"
                },
                {
                    "en": "the Netherlands",
                    "ua": "Netherlands"
                }
            ]
        },
        {
            "label": "Why THE?",
            "color": "amber",
            "description": "The article <strong>the</strong> is required if:",
            "examples": [
                {
                    "en": "1. The name contains "States", "Kingdom", "Republic"",
                    "ua": "the United States, the Czech Republic"
                },
                {
                    "en": "2. Plural name",
                    "ua": "the Netherlands, the Philippines"
                },
                {
                    "en": "3. Historical name from Union/Federation",
                    "ua": "the Soviet Union (historical)"
                }
            ],
            "note": "📌 Exceptions: the Gambia, the Congo, the Sudan (historical)."
        }
    ]
}

{
    "title": "3. Cities and capitals - without an article",
    "sections": [
        {
            "label": "All cities - Ø",
            "color": "emerald",
            "description": "<strong>All cities</strong> are used <strong>without an article</strong>.",
            "examples": [
                {
                    "en": "Kyiv, Lviv, Odesa, Kharkiv",
                    "ua": "Kyiv, Lviv, Odesa, Kharkiv"
                },
                {
                    "en": "London, Paris, Berlin, Rome",
                    "ua": "London, Paris, Berlin, Rome"
                },
                {
                    "en": "New York, Los Angeles, Tokyo",
                    "ua": "New York, Los Angeles, Tokyo"
                },
                {
                    "en": "I was born in Kyiv.",
                    "ua": "I was born in Kyiv."
                }
            ]
        },
        {
            "label": "Exceptions with cities",
            "color": "rose",
            "description": "Very rare exceptions (historically):",
            "examples": [
                {
                    "en": "The Hague is the only city from the",
                    "ua": "Capital of the Netherlands"
                },
                {
                    "en": "I went to The Hague.",
                    "ua": "I went to The Hague."
                }
            ],
            "note": "📌 The Hague is practically the only exception among cities!"
        }
    ]
}

{
    "title": "4. Continents - no article",
    "sections": [
        {
            "label": "All continents - Ø",
            "color": "emerald",
            "description": "<strong>Continents</strong> always <strong>no article</strong>.",
            "examples": [
                {
                    "en": "Europe, Asia, Africa",
                    "ua": "Europe, Asia, Africa"
                },
                {
                    "en": "North America, South America",
                    "ua": "North America, South America"
                },
                {
                    "en": "Australia, Antarctica",
                    "ua": "Australia, Antarctica"
                },
                {
                    "en": "I traveled across Europe.",
                    "ua": "I traveled across Europe."
                }
            ]
        }
    ]
}

{
    "title": "5. Oceans, seas, rivers - with the article THE",
    "sections": [
        {
            "label": "Oceans - THE",
            "color": "blue",
            "description": "<strong>All oceans</strong> are used with the article <strong>the</strong>.",
            "examples": [
                {
                    "en": "the Pacific Ocean",
                    "ua": "Pacific Ocean"
                },
                {
                    "en": "the Atlantic Ocean",
                    "ua": "Atlantic Ocean"
                },
                {
                    "en": "the Indian Ocean",
                    "ua": "Indian Ocean"
                },
                {
                    "en": "the Arctic Ocean",
                    "ua": "Arctic Ocean"
                }
            ]
        },
        {
            "label": "Sea - THE",
            "color": "sky",
            "description": "<strong>All seas</strong> are used with the article <strong>the</strong>.",
            "examples": [
                {
                    "en": "the Black Sea",
                    "ua": "Black Sea"
                },
                {
                    "en": "the Mediterranean Sea",
                    "ua": "Mediterranean Sea"
                },
                {
                    "en": "the Baltic Sea",
                    "ua": "Baltic Sea"
                },
                {
                    "en": "the Red Sea",
                    "ua": "Red Sea"
                }
            ]
        },
        {
            "label": "Rivers - THE",
            "color": "purple",
            "description": "<strong>All rivers</strong> are used with the article <strong>the</strong>.",
            "examples": [
                {
                    "en": "the Dnipro (the Dnieper)",
                    "ua": "Dnipro"
                },
                {
                    "en": "the Thames",
                    "ua": "Thamsa"
                },
                {
                    "en": "the Danube",
                    "ua": "Danuy"
                },
                {
                    "en": "the Amazon, the Nile",
                    "ua": "Amazon, the Nile"
                }
            ]
        }
    ]
}

{
    "title": "6. Mountains - depends on shape",
    "sections": [
        {
            "label": "Individual peaks - Ø",
            "color": "emerald",
            "description": "<strong>Individual mountains</strong> (with Mount, Peak) - <strong>no article</strong>.",
            "examples": [
                {
                    "en": "Mount Everest",
                    "ua": "Mount Everest"
                },
                {
                    "en": "Mount Kilimanjaro. THE",
                    "ua": "Гора Кіліманджаро"
                },
                {
                    "en": "Hoverla (найвища в Україні)",
                    "ua": "Говерла"
                },
                {
                    "en": "I climbed Mount Everest.",
                    "ua": "Я піднявся на Еверест."
                }
            ]
        },
        {
            "label": "Гірські системи — THE",
            "color": "blue",
            "description": "<strong>Mountain systems</strong> (plural mountains) — with the article <strong>the</strong>.",
            "examples": [
                {
                    "en": "the Alps",
                    "ua": "Alps"
                },
                {
                    "en": "the Carpathians",
                    "ua": "Carpathians"
                },
                {
                    "en": "the Himalayas",
                    "ua": "Himalayas"
                },
                {
                    "en": "the Rockies (the Rocky Mountains)",
                    "ua": "Rocky Mountains"
                }
            ]
        }
    ]
}

{
    "title": "7. Lakes - depends on the form",
    "sections": [
        {
            "label": "Lake + name - Ø",
            "color": "emerald",
            "description": "If there is the word <strong>Lake</strong> before the name - <strong>no article</strong>.",
            "examples": [
                {
                    "en": "Lake Baikal",
                    "ua": "Lake Baikal"
                },
                {
                    "en": "Lake Superior",
                    "ua": "Lake Upper"
                },
                {
                    "en": "Lake Geneva",
                    "ua": "Lake Geneva"
                },
                {
                    "en": "I visited Lake Baikal.",
                    "ua": "I visited Lake Baikal."
                }
            ]
        },
        {
            "label": "The name without Lake is THE",
            "color": "blue",
            "description": "If <strong>there is no word Lake</strong> - with an article <strong>the</strong>.",
            "examples": [
                {
                    "en": "the Baikal (without the word Lake)",
                    "ua": "Baikal"
                },
                {
                    "en": "the Great Lakes",
                    "ua": "Great lakes (group)"
                }
            ],
            "note": "📌 The group of lakes is always with the."
        }
    ]
}

{
    "title": "8. Islands - depends on the number Jamaica",
    "sections": [
        {
            "label": "Окремий острів — Ø",
            "color": "emerald",
            "description": "<strong>Окремі острови</strong> — <strong>без артикля</strong>.",
            "examples": [
                {
                    "en": "Cyprus, Sicily, Crete",
                    "ua": "Кіпр, Сицилія, Крит"
                },
                {
                    "en": "Madagascar, Jamaica",
                    "ua": "Madagascar, Jamaica"
                },
                {
                    "en": "I went to Cyprus.",
                    "ua": "I went to Cyprus."
                }
            ]
        },
        {
            "label": "Groups of islands - THE",
            "color": "blue",
            "description": "<strong>Groups of islands</strong> (archipelagos) - with article The Canary Islands",
            "examples": [
                {
                    "en": "the Canary Islands",
                    "ua": "Канарські острови"
                },
                {
                    "en": "the British Isles",
                    "ua": "Британські острови"
                },
                {
                    "en": "the Bahamas",
                    "ua": "Багамські острови"
                },
                {
                    "en": "the Philippines",
                    "ua": "Philippines (both country and islands)"
                }
            ]
        }
    ]
}

{
    "title": "9. Deserts, canals, bays - from THE",
    "sections": [
        {
            "label": "Deserts - THE",
            "color": "amber",
            "description": "<strong>All deserts</strong> are used with the article <strong>the</strong>.",
            "examples": [
                {
                    "en": "the Sahara (Desert)",
                    "ua": "Sahara"
                },
                {
                    "en": "the Gobi Desert",
                    "ua": "Gobi Desert"
                },
                {
                    "en": "the Kalahari",
                    "ua": "Kalahari"
                }
            ]
        },
        {
            "label": "Channels - THE",
            "color": "sky",
            "description": "<strong>Channels</strong> are used with the article <strong>the</strong>.",
            "examples": [
                {
                    "en": "the Suez Canal",
                    "ua": "Suez Canal"
                },
                {
                    "en": "the Panama Canal",
                    "ua": "Panama Canal"
                },
                {
                    "en": "the English Channel",
                    "ua": "La Manche "
                }
            ]
        },
        {
            "label": "Bays — THE",
            "color": "purple",
            "description": "<strong>Gulfs</strong> are used with the article <strong>the</strong>.",
            "examples": [
                {
                    "en": "the Persian Gulf",
                    "ua": "Persian Gulf"
                },
                {
                    "en": "the Gulf of Mexico",
                    "ua": "Mexican Gulf"
                }
            ]
        }
    ]
}

{
    "title": "10. Comparison table",
    "intro": "Quick reference: when the article is needed the:",
    "rows": [
        {
            "en": "Countries (most)",
            "ua": "Countries (most)",
            "note": "Ø: Ukraine, France, Japan"
        },
        {
            "en": "Countries (unions)",
            "ua": "Countries (unions)",
            "note": "THE: the USA, the UK, the Netherlands"
        },
        {
            "en": "Cities",
            "ua": "Cities",
            "note": "Ø: Kyiv, London, Paris (except: The Hague)"
        },
        {
            "en": "Continents",
            "ua": "Continents",
            "note": "Ø: Europe, Asia, Africa"
        },
        {
            "en": "Oceans, seas, rivers",
            "ua": "Oceans, seas, rivers",
            "note": "THE: the Pacific, the Dnipro, the Black Sea"
        },
        {
            "en": "Mountains (single)",
            "ua": "Mountains (single)",
            "note": "Ø: Mount Everest, Hoverla"
        },
        {
            "en": "Mountains (ranges)[[[CODX_5]]]Mountains systems",
            "ua": "Гірські системи",
            "note": "THE: the Alps, the Carpathians"
        },
        {
            "en": "Lakes (with Lake)",
            "ua": "Ozera (with Lake)",
            "note": "Ø: Lake Baikal"
        },
        {
            "en": "Islands (single)",
            "ua": "Islands (single)",
            "note": "Ø: Cyprus, Sicily"
        },
        {
            "en": "Islands (groups)",
            "ua": "Groups of islands",
            "note": "THE: the Canary Islands, the Bahamas"
        }
    ],
    "warning": "📌 General rule: if the name is <strong>plural</strong> or contains <strong>union/republic</strong> - use <strong>the</strong>!"
}

{
    "title": "11. Typical errors",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Article before Ukraine.",
            "wrong": "I live in the Ukraine.",
            "right": "​​​​ <span class="font-mono">I live in Ukraine.</span>"
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Without article in front of the river.",
            "wrong": "Dnipro is a long river.",
            "right": "​​​​ <span class="font-mono">The Dnipro is a long river.</span>"
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Article in front of Mount Everest.",
            "wrong": "I climbed the Mount Everest.",
            "right": "​​​​ <span class="font-mono">I climbed Mount Everest.</span>"
        },
        {
            "label": "Error 4",
            "color": "purple",
            "title": "Forget the before USA.",
            "wrong": "I visited USA.",
            "right": "​​​​ <span class="font-mono">I visited the USA.</span>"
        }
    ]
}

{
    "title": "13. Practice",
    "select_title": "Exercise 1. Do you need an article? the)",
    "select_intro": "Визначте, чи потрібен артикль the з цими назвами.",
    "selects": [
        {
            "label": "___ Pacific Ocean (Ø / the)",
            "prompt": "Потрібен артикль?"
        },
        {
            "label": "___ London (Ø / the)",
            "prompt": "Need an article?"
        },
        {
            "label": "___ Alps (Ø / the)",
            "prompt": "Need an article?"
        },
        {
            "label": "___ USA (Ø / the)",
            "prompt": "Need an article?"
        }
    ],
    "options": [
        "Ø (without article)",
        "the"
    ],
    "input_title": "Exercise 2. Fill in the blanks",
    "input_intro": "Write Ø (without article) or the.",
    "inputs": [
        {
            "before": "I live in ___ Ukraine.",
            "after": "→"
        },
        {
            "before": "___ Dnipro is a beautiful river.",
            "after": "→"
        },
        {
            "before": "I climbed ___ Mount Everest.",
            "after": "→"
        }
    ],
    "rephrase_title": "Exercise 3. Correct the error",
    "rephrase_intro": "Find and correct the error with article.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "I live in the Ukraine.",
            "example_target": "I live in Ukraine."
        },
        {
            "original": "1. Thames is a long river.",
            "placeholder": "Fix the bug"
        },
        {
            "original": "2. I visited the Mount Everest.",
            "placeholder": "Correct the error"
        }
    ]
}

{
    "title": "Other pages from the category Nouns, articles and quantity",
    "items": [
        {
            "label": "Articles with geographical names",
            "current": true
        },
        {
            "label": "Articles A / An / The — Articles",
            "current": false
        },
        {
            "label": "Zero Article — Zero article",
            "current": false
        },
        {
            "label": "No / None / Neither / Either",
            "current": false
        }
    ]
}
